WITH src AS (SELECT i.indexrelid AS object_id, sut.relname AS table_name, sut.schemaname AS table_owner, ipc.relname AS index_name, ns.nspname AS index_owner, i.indrelid AS table_object_id, i.indnatts AS indexed_column_count, i.indnkeyatts AS indexed_keyed_column_count, i.indisunique AS is_unique, i.indisprimary AS is_primary, i.indisexclusion AS is_exclusion, i.indimmediate AS is_immediate, i.indisclustered AS is_clustered, i.indisvalid AS is_valid, i.indcheckxmin AS is_check_xmin, i.indisready AS is_ready, i.indislive AS is_live, i.indisreplident AS is_replica_identity, COALESCE(psui.idx_blks_read, 0) AS index_block_read, COALESCE(psui.idx_blks_hit, 0) AS index_blocks_hit, COALESCE(p.idx_scan, 0) AS index_scan, COALESCE(p.idx_tup_read, 0) AS index_tuples_read, COALESCE(p.idx_tup_fetch, 0) AS index_tuples_fetched, PG_RELATION_SIZE(i.indexrelid) AS index_size_bytes, PG_GET_INDEXDEF(i.indexrelid) AS index_definition FROM pg_index AS i JOIN pg_class AS ipc ON (i.indexrelid = ipc.oid) JOIN pg_namespace AS ns ON (ipc.relnamespace = ns.oid) JOIN pg_stat_user_tables AS sut ON (i.indrelid = sut.relid) LEFT JOIN pg_catalog.pg_statio_user_indexes AS psui ON (i.indexrelid = psui.indexrelid) LEFT JOIN pg_catalog.pg_stat_user_indexes AS p ON (i.indexrelid = p.indexrelid) WHERE ns.nspname <> ALL(ARRAY['pg_catalog', 'information_schema']) AND NOT ns.nspname ~ '^pg_toast') SELECT CHR(34) || :PKEY || CHR(34) AS pkey, CHR(34) || :DMA_SOURCE_ID || CHR(34) AS dma_source_id, CHR(34) || :DMA_MANUAL_ID || CHR(34) AS dma_manual_id, src.object_id, CHR(34) || REPLACE(src.table_name, CHR(34), CHR(30)) || CHR(34) AS table_name, CHR(34) || REPLACE(src.table_owner, CHR(34), CHR(30)) || CHR(34) AS table_owner, CHR(34) || REPLACE(src.index_name, CHR(34), CHR(30)) || CHR(34) AS index_name, CHR(34) || REPLACE(src.index_owner, CHR(34), CHR(30)) || CHR(34) AS index_owner, src.table_object_id, src.indexed_column_count, src.indexed_keyed_column_count, src.is_unique, src.is_primary, src.is_exclusion, src.is_immediate, src.is_clustered, src.is_valid, src.is_check_xmin, src.is_ready, src.is_live, src.is_replica_identity, src.index_block_read, src.index_blocks_hit, src.index_scan, src.index_tuples_read, src.index_tuples_fetched, src.index_size_bytes, src.index_definition FROM src